  const gradeTableQuestion = async (qIdx, q, targetInputs = null) => {
    setGradingLoading(prev => ({ ...prev, [qIdx]: true }));
    const inputs = targetInputs || Object.keys(q.answers || {});
    const activeAnswers = showExam ? examTableAnswersRef.current : tableAnswersRef.current;
    const activeSetGradingResults = showExam ? setExamTableGradingResults : setTableGradingResults;
    
    const currentGrading = showExam ? examTableGradingResultsRef.current : tableGradingResultsRef.current;
    const nextGrading = { ...currentGrading };
    
    const progressId = 'grade_' + Math.random().toString(36).substring(2, 9);
    startProgressPolling(progressId);

    const promises = inputs.map(async (inputId) => {
      const userAnswer = activeAnswers[`${qIdx}_${inputId}`] || '';
      const correctAnswer = q?.answers?.[inputId] || '';
      
      let rowHeader = '';
      let colHeader = '';
      if (q.tableData && q.tableData.rows && q.tableData.headers) {
        q.tableData.rows.forEach((row) => {
          row.forEach((cell, colIdx) => {
            if (typeof cell === 'string' && cell.includes(`[${inputId}]`)) {
              rowHeader = row[0] || '';
              colHeader = q.tableData.headers[colIdx] || '';
            }
          });
        });
      }
      if (!rowHeader && q.comparisonTableData && q.comparisonTableData.rows && q.comparisonTableData.headers) {
        q.comparisonTableData.rows.forEach((row) => {
          row.forEach((cell, colIdx) => {
            if (typeof cell === 'string' && cell.includes(`[${inputId}]`)) {
              rowHeader = row[0] || '';
              colHeader = q.comparisonTableData.headers[colIdx] || '';
            }
          });
        });
      }
      
      try {
        const res = await fetch(`${API_BASE}/api/grade-subjective`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            question: q.question,
            correctAnswer,
            userAnswer,
            rowHeader,
            colHeader,
            explanation: q.explanation || q.answer || '',
            category: showExam ? examTopic?.category : selectedTopic?.category,
            progressId
          })
        });
        const data = await res.json();
        nextGrading[`${qIdx}_${inputId}`] = {
          isCorrect: data.isCorrect,
          score: data.score,
          reason: data.reason,
          suggestedModelAnswer: data.suggestedModelAnswer
        };
      } catch (err) {
        console.error('Grading error:', err);
        const normalize = (s) => (s || '').trim().toLowerCase().replace(/\s+/g, '');
        const isCorrect = normalize(userAnswer) === normalize(correctAnswer);
        nextGrading[`${qIdx}_${inputId}`] = {
          isCorrect,
          score: isCorrect ? 10 : 0,
          reason: isCorrect ? '단순 일치(로컬 채점)' : '모범 답안과 불일치'
        };
      }
    });

    try {
      await Promise.all(promises);
      
      activeSetGradingResults(nextGrading);
      if (showExam) {
        examTableGradingResultsRef.current = nextGrading;
      } else {
        tableGradingResultsRef.current = nextGrading;
      }

      // DB 저장 (디바운스 적용)
      if (!showExam && selectedTopic && selectedTopic.id && aiQuestions.length > 0 && !selectedTopic.isReadOnly) {
        lastSyncStateRef.current.tableGradingResults = nextGrading;
        saveActiveSessionDebounced();
      }

      if (showExam && examQuestions.length > 0 && !loadingExam) {
        saveActiveSessionDebounced();
      }

      stopProgressPolling('채점 완료!', 100);
      return nextGrading;
    } catch (e) {
      stopProgressPolling('채점 실패', 100, false);
    } finally {
      setGradingLoading(prev => ({ ...prev, [qIdx]: false }));
    }
  };

