  const getReviewTotalScore = () => {
    let total = 0;
    const M = aiQuestions.length;
    if (M === 0) return 0;
    const baseWeight = Math.floor(100 / M);
    const remainder = 100 - (baseWeight * M);

    aiQuestions.forEach((q, idx) => {
      const W = idx < remainder ? (baseWeight + 1) : baseWeight;
      const isMC = q.type === '객관식' || (q.options && q.options.length > 0);

      if (isMC) {
        const userAnswer = selectedAnswers[idx];
        const isCorrect = userAnswer !== undefined && userAnswer === q.answer;
        if (isCorrect) {
          total += W;
        }
      } else if (q.type === '주관식 (앞글자)') {
        let sumVal = 0;
        let countVal = 0;
        
        const rowCount = q.tableData?.rows?.length || 0;
        for (let rIdx = 0; rIdx < rowCount; rIdx++) {
          // Add acronym letter score (max 10)
          const letterGrading = tableGradingResults[`${idx}_ROW_${rIdx}_ACRONYM`];
          if (letterGrading && letterGrading.score !== undefined) {
            sumVal += letterGrading.score;
          }
          countVal++;
          
          // Add content description score (max 10)
          const rowGrading = tableGradingResults[`${idx}_ROW_${rIdx}_COMB`];
          if (rowGrading && rowGrading.score !== undefined) {
            sumVal += rowGrading.score;
          }
          countVal++;
        }
        if (countVal > 0) {
          total += (sumVal / (countVal * 10)) * W;
        }
      } else if (q.tableData || q.comparisonTableData) {
        const inputIds = Object.keys(q.answers || {});
        let sumVal = 0;
        let countVal = inputIds.length;
        inputIds.forEach(inputId => {
          const grading = tableGradingResults[`${idx}_${inputId}`];
          if (grading && grading.score !== undefined) {
            sumVal += grading.score;
          }
        });
        if (countVal > 0) {
          total += (sumVal / (countVal * 10)) * W;
        }
      } else {
        const grading = tableGradingResults[`${idx}_INPUT`];
        if (grading && grading.score !== undefined) {
          total += (grading.score / 10) * W;
        }
      }
    });
    return Math.round(total * 10) / 10;
  };

  const getDisplayReviewScore = () => {
    if (!selectedTopic) return 0;
    if (selectedTopic.isReadOnly) {
      const schedId = selectedTopic.schedule_id;
      if (schedId) {
        const todaySched = todayReviews.find(r => r.schedule_id === schedId);
        if (todaySched && todaySched.score !== undefined && todaySched.score !== null) {
          return todaySched.score;
        }
        for (const topic of allTopics) {
          if (topic.schedules) {
            const s = topic.schedules.find(x => x.id === schedId);
            if (s && s.score !== undefined && s.score !== null) {
              return s.score;
            }
          }
        }
      }
    }
    return getReviewTotalScore();
  };

  const getExamTotalScore = () => {
    let total = 0;
    const M = examQuestions.length;
    if (M === 0) return 0;
    const baseWeight = Math.floor(100 / M);
    const remainder = 100 - (baseWeight * M);

    examQuestions.forEach((q, idx) => {
      const W = idx < remainder ? (baseWeight + 1) : baseWeight;
      const isMC = q.type === '객관식' || (q.options && q.options.length > 0);

      if (isMC) {
        const userAnswer = examAnswers[idx];
        const normalizeAns = (s) => (s || '').replace(/^\d+\.\s*/, '').trim();
        const isCorrect = userAnswer !== undefined && normalizeAns(userAnswer) === normalizeAns(q.answer);
        if (isCorrect) {
          total += W;
        }
      } else if (q.tableData || q.comparisonTableData) {
        const inputIds = Object.keys(q.answers || {});
        let sumVal = 0;
        let countVal = inputIds.length;
        inputIds.forEach(inputId => {
          const grading = examTableGradingResults[`${idx}_${inputId}`];
          if (grading && grading.score !== undefined) {
            sumVal += grading.score;
          }
        });
        if (countVal > 0) {
          total += (sumVal / (countVal * 10)) * W;
        }
      } else {
        const grading = examTableGradingResults[`${idx}_INPUT`];
        if (grading && grading.score !== undefined) {
          total += (grading.score / 10) * W;
        }
      }
    });
    return Math.round(total * 10) / 10;
  };

  const gradeSubjectiveQuestion = async (qIdx, q) => {
    setGradingLoading(prev => ({ ...prev, [qIdx]: true }));
    const activeAnswers = showExam ? examTableAnswersRef.current : tableAnswersRef.current;
    const activeSetGradingResults = showExam ? setExamTableGradingResults : setTableGradingResults;

    const userAnswer = activeAnswers[`${qIdx}_INPUT`] || '';
    const correctAnswer = q.answer || q.concept || '';
    
    const progressId = 'grade_' + Math.random().toString(36).substring(2, 9);
    startProgressPolling(progressId);

    let newResult = null;
    try {
      const res = await fetch(`${API_BASE}/api/grade-subjective`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          question: q.question,
          correctAnswer,
          userAnswer,
          explanation: q.explanation || '',
          category: showExam ? examTopic?.category : selectedTopic?.category,
          progressId
        })
      });
      const data = await res.json();
      newResult = {
        isCorrect: data.isCorrect,
        score: data.score,
        reason: data.reason,
        suggestedModelAnswer: data.suggestedModelAnswer
      };
      stopProgressPolling('채점 완료!', 100);
    } catch (err) {
      console.error('Grading error:', err);
      const normalize = (s) => (s || '').trim().toLowerCase().replace(/\s+/g, '');
      const isCorrect = normalize(userAnswer) === normalize(correctAnswer);
      newResult = {
        isCorrect,
        score: isCorrect ? 10 : 0,
        reason: isCorrect ? '단순 일치(로컬 채점)' : '모범 답안과 불일치'
      };
      stopProgressPolling('채점 실패', 100, false);
    }

    if (newResult) {
      activeSetGradingResults(prev => {
        const nextResults = {
          ...prev,
          [`${qIdx}_INPUT`]: newResult
        };

        // DB 저장 (디바운스 적용)
        if (!showExam && selectedTopic && selectedTopic.id && aiQuestions.length > 0 && !selectedTopic.isReadOnly) {
          lastSyncStateRef.current.tableGradingResults = nextResults;
          saveActiveSessionDebounced();
        }

        if (showExam && examQuestions.length > 0 && !loadingExam) {
          saveActiveSessionDebounced();
        }

        return nextResults;
      });
    }

    setGradingLoading(prev => ({ ...prev, [qIdx]: false }));
    return newResult;
  };

  const [isFallback, setIsFallback] = useState(false);
  const [aiError, setAiError] = useState('');
  const [openSections, setOpenSections] = useState({}); // { 'qIdx-sIdx': bool } for section accordion
  const [questionFeedback, setQuestionFeedback] = useState({}); // Stores upvotes/downvotes of questions { `${topic_id}_${questionText}`: 'upvote' | 'downvote' }
  
  // Exam mode state
  const [examQuestions, setExamQuestions] = useState([]);
  const [showExam, setShowExam] = useState(() => localStorage.getItem('anti_show_exam') === 'true');
  const [loadingExam, setLoadingExam] = useState(() => localStorage.getItem('anti_show_exam') === 'true');
  const [examTopic, setExamTopic] = useState(null);
  const [examRevealed, setExamRevealed] = useState({});
