  // PIN Code entry restriction states
  const [isPinVerified, setIsPinVerified] = useState(() => sessionStorage.getItem('pin_verified') === 'true');
  const wasPinVerifiedOnMount = useRef(sessionStorage.getItem('pin_verified') === 'true');
