  const lastTickRef = useRef(Date.now());
  const tickCountRef = useRef(0);
  const wasInBackgroundRef = useRef(false);

  // Interval to update the tick timestamp while visible
  useEffect(() => {
    if (!isPinVerified || isDesktop) return;
    
    // Check if the user just verified the PIN and logged in
    const justLoggedIn = sessionStorage.getItem('just_logged_in') === 'true';
    if (justLoggedIn) {
      sessionStorage.removeItem('just_logged_in');
      tickCountRef.current = 0;
      lastTickRef.current = Date.now();
      localStorage.setItem('anti_last_tick_time', String(Date.now()));
    } else {
      // Re-initialize from localStorage to handle fresh tab reloads/suspensions
      const lastTickStr = localStorage.getItem('anti_last_tick_time');
      const lastTickVal = lastTickStr ? parseInt(lastTickStr, 10) : Date.now();
      lastTickRef.current = lastTickVal;
      tickCountRef.current = 10; // Keep it outside the grace period
    }

    const interval = setInterval(() => {
      // Only tick when the tab is visible to keep lastTickRef fresh
      if (document.visibilityState === 'visible') {
        const now = Date.now();
        lastTickRef.current = now;
        localStorage.setItem('anti_last_tick_time', String(now));
        tickCountRef.current += 1;
      }
    }, 1000);
    
    return () => clearInterval(interval);
  }, [isPinVerified, isDesktop]);



  // Listener to trigger the quiz immediately on visibility change (wake up / app return)
  useEffect(() => {
    if (!isPinVerified || isDesktop) return;

    const handleWakeup = () => {
      // Bypass during the first 5 ticks (grace period) of a fresh login session
      if (tickCountRef.current <= 5) {
        return;
      }

      const isVisible = document.visibilityState === 'visible' || document.hasFocus?.();
      if (isVisible) {
        if (wasInBackgroundRef.current && isLockscreenQuizEnabled) {
          wasInBackgroundRef.current = false;
          triggerLockscreenQuiz();
        }
      }
    };

    const handleBlur = () => {
      wasInBackgroundRef.current = true;
    };

    const handleVisibility = () => {
      if (document.visibilityState === 'hidden') {
        wasInBackgroundRef.current = true;
      } else if (document.visibilityState === 'visible') {
        handleWakeup();
      }
    };

    document.addEventListener('visibilitychange', handleVisibility);
    window.addEventListener('blur', handleBlur);
    window.addEventListener('focus', handleWakeup);
    window.addEventListener('pageshow', handleWakeup);

    return () => {
      document.removeEventListener('visibilitychange', handleVisibility);
      window.removeEventListener('blur', handleBlur);
      window.removeEventListener('focus', handleWakeup);
      window.removeEventListener('pageshow', handleWakeup);
    };
  }, [isPinVerified, isDesktop, isLockscreenQuizEnabled]);

  // Proactive trigger of lockscreen quiz on app startup, mount, and refresh when enabled
  useEffect(() => {
    if (isPinVerified && !isDesktop && isLockscreenQuizEnabled) {
      if (wasPinVerifiedOnMount.current) {
        wasPinVerifiedOnMount.current = false;
        return;
      }
      triggerLockscreenQuiz();
    }
  }, [isPinVerified, isDesktop, isLockscreenQuizEnabled]);

  // [모바일 세로 수평 드래그 차단 및 가로 스크롤 구역 예외 적용]
  // 표/수식 영역 안의 가로 터치 스크롤은 부드럽게 허용하고, 그 외 영역의 좌우 드래그 및 화면 쏠림만 완벽하게 차단한다.
  useEffect(() => {
    let _startX = 0;
    let _startY = 0;

    const _onTouchStart = (e) => {
      if (e.touches && e.touches.length > 0) {
        _startX = e.touches[0].clientX;
        _startY = e.touches[0].clientY;
      }
    };

    const _onTouchMove = (e) => {
      // 세로 모드 좁은 화면에서만 동작
      if (window.innerWidth > 767) return;

      const deltaX = Math.abs(e.touches[0].clientX - _startX);
      const deltaY = Math.abs(e.touches[0].clientY - _startY);

      // 수평 스와이프가 수직보다 강할 때
      if (deltaX > deltaY && deltaX > 5) {
        // 터치 대상이 가로 스크롤 가능한 컨테이너 안인지 확인
        let el = e.target;
        let insideHScroll = false;
        while (el && el !== document.body) {
          if (el.classList && (
            el.classList.contains('markdown-table-container') ||
            el.classList.contains('overflow-x-auto') ||
            el.classList.contains('overflow-auto') ||
            el.classList.contains('table-quiz-container') ||
            el.classList.contains('landscape-overflow-x-auto') ||
            el.classList.contains('formula-scroll-container')
          )) {
            insideHScroll = true;
            break;
          }
          el = el.parentElement;
        }

        // 가로 스크롤 구역이 아니면 페이지의 수평 드래그 이동을 막는다.
        if (!insideHScroll) {
          if (e.cancelable) {
            e.preventDefault();
          }
        }
      }
    };

    document.addEventListener('touchstart', _onTouchStart, { passive: true });
    document.addEventListener('touchmove', _onTouchMove, { passive: false }); // ← passive: false 필수

    return () => {
      document.removeEventListener('touchstart', _onTouchStart);
      document.removeEventListener('touchmove', _onTouchMove);
    };
  }, []); // 마운트 시 1회만 등록

  const chatBodyRef = useRef(null);
