  // ── Gemini Sidebar Chat Handler ───────────────────────────────
  const handleSendChat = async (customMessage, overrideAcronymMode = false) => {
    const userMessage = (typeof customMessage === 'string' ? customMessage : chatInput).trim();
    if ((!userMessage && !attachedImage) || isChatLoading) return;
    
    const currentAttachedImage = attachedImage;
    if (typeof customMessage !== 'string') {
      setChatInput('');
    }
    setAttachedImage(null);
    
    // 공식이 첨부되어 있다면 프롬프트 상단에 메타 정보로 추가하고 즉시 비웁니다.
    let apiMessage = userMessage;
    if (tutorAttachedFormula) {
      apiMessage = `[수험생이 첨부한 공식: ${tutorAttachedFormula}]\n\n${userMessage}`;
    }
    const sentAttachedFormula = tutorAttachedFormula;
    setTutorAttachedFormula(null); // 전송 후 즉시 비우기

    const userMsgIdx = chatHistory.length;
    let displayMessage = userMessage;
    if (sentAttachedFormula) {
      displayMessage = `$$${sentAttachedFormula}$$\n\n${userMessage}`;
    }
    
    const newUserMsg = { role: 'user', text: displayMessage, image: currentAttachedImage };
    const historyWithUser = [...chatHistoryRef.current, newUserMsg];
    setChatHistory(historyWithUser);
    chatHistoryRef.current = historyWithUser;
    saveChatToNeon(historyWithUser);
    
    setIsChatLoading(true);

    requestAnimationFrame(() => {
      if (chatBodyRef.current) chatBodyRef.current.scrollTop = chatBodyRef.current.scrollHeight;
    });

    const progressId = 'tutor_' + Math.random().toString(36).substring(2, 9);
    startProgressPolling(progressId);

    try {
      const data = await safeFetchJson(`${API_BASE}/api/chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          history: historyWithUser.map(h => ({ role: h.role, text: h.text })), 
          message: apiMessage,
          image: currentAttachedImage ? { mimeType: currentAttachedImage.mimeType, data: currentAttachedImage.data } : null,
          acronymMode: overrideAcronymMode || acronymModeActive,
          progressId
        })
      });
      stopProgressPolling('답변 생성이 완료되었습니다!', 100);
      
      const newModelMsg = { role: 'model', text: data.text };
      const historyWithModel = [...chatHistoryRef.current, newModelMsg];
      setChatHistory(historyWithModel);
      chatHistoryRef.current = historyWithModel;
      saveChatToNeon(historyWithModel);
    } catch (err) {
      stopProgressPolling('답변 생성 실패', 100, false);
      
      const newErrorMsg = { role: 'model', text: `오류가 발생했습니다: ${err.message}` };
      const historyWithError = [...chatHistoryRef.current, newErrorMsg];
      setChatHistory(historyWithError);
      chatHistoryRef.current = historyWithError;
      saveChatToNeon(historyWithError);
    } finally {
      setIsChatLoading(false);
      scrollToLastTutorResponse(chatBodyRef.current);
    }
  };

  const handleAcronymPromptRequest = (chatType = 'sidebar') => {
    setAcronymPromptTopic('');
    setAcronymPromptCount('4');
    setAcronymRecommendations([]);
    setIsAcronymRecommending(false);
    setShowAcronymPromptModal(true);
  };

  const handleGenerateAcronymSubmit = async () => {
    await handleGenerateAcronymSubmitWithTopic(acronymPromptTopic);
  };

  const handleGenerateAcronymSubmitWithTopic = async (topicVal, isRecommendation = false) => {
    const topic = topicVal.trim();
    const count = parseInt(acronymPromptCount, 10) || 4;
    if (!topic) return;

    // Immediately close modal & clean up prompt state to avoid duplicate submits
    setShowAcronymPromptModal(false);
    setAcronymPromptTopic('');

    showNotification(`[${topic}] 앞글자 암기법 생성을 시작했습니다.`, 'info');

    // Create a temporary loading card in the acronyms list
    const tempId = 'acronym-loading-' + Date.now();
    const newLoadingAcronym = {
      id: tempId,
      title: topic,
      content: '', // empty content represents loading state
      isLoading: true,
      createdAt: new Date().toISOString()
    };
    
    setFormulaAcronyms(prev => [newLoadingAcronym, ...prev]);

    try {
      const query = `${topic}에 대한 앞글자(두문자) 암기법을 생성해줘. 총 ${count}개 항목으로 구성해줘.`;
      
      const res = await fetch(`${API_BASE}/api/chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          history: [],
          message: query,
          image: null,
          acronymMode: true
        })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || '앞글자 생성 실패');

      let aiText = data.text || '';
      
      let parsedTitle = topic;
      const titleMatch = aiText.match(/^제목:\s*([^\n]+)/m);
      if (titleMatch) {
        parsedTitle = titleMatch[1].trim();
        aiText = aiText.replace(/^제목:[^\n]*\n?/m, '');
      }

      const finalContent = aiText.trim();

      setFormulaAcronyms(prev => {
        const updated = prev.map(ac => {
          if (ac.id === tempId) {
            return {
              id: 'acronym-' + Date.now(),
              title: parsedTitle,
              content: finalContent,
              createdAt: new Date().toISOString()
            };
          }
          return ac;
        });
        handleSaveFormulaAcronyms(updated, false);
        return updated;
      });

      showNotification(`[${parsedTitle}] 앞글자 암기법이 생성되었습니다!`, 'success');
      setExportAddedTarget({ type: 'acronym', title: parsedTitle });
    } catch (err) {
      console.error('Failed to generate acronym:', err);
      setFormulaAcronyms(prev => prev.filter(ac => ac.id !== tempId));
      showNotification(`생성 실패: ${err.message}`, 'error');
    }
  };

