                  const clickX = e.clientX - rect.left;
                  if (clickX > e.currentTarget.clientWidth) {
                    const now = Date.now();
                    if (now - lastExamScrollbarClickTime.current < 400) {
                      scrollToLastSolvedQuestion(true);
                    }
                    lastExamScrollbarClickTime.current = now;
                  }
